const cur = msg.payload.current;
const temp      = cur.temperature_2m;
const humidity  = cur.relative_humidity_2m;
const pressure  = cur.pressure_msl;
const windSpeed = cur.wind_speed_10m;
const windDir   = cur.wind_direction_10m;

global.set('outdoor_temp',       temp);
global.set('outdoor_humidity',   humidity);
global.set('outdoor_pressure',   pressure);
global.set('outdoor_wind_speed', windSpeed);
global.set('outdoor_wind_dir',   windDir);

const todaysYield = global.get('total_yield_today') || 0;
const irradiance  = global.get('irradiance_wm2')    || 0;

node.status({fill:'green', shape:'dot', text:`${temp}°C — ${irradiance} W/m² — ${todaysYield.toFixed(2)} kWh`});

const heatMsg = {
    topic:   'santuario/heat/1/venus',
    payload: JSON.stringify({
        Temperature:     temp,
        TemperatureType: 4,
        Humidity:        humidity,
        Pressure:        pressure
    })
};
const meteoMsg = {
    topic:   'santuario/meteo/venus',
    payload: JSON.stringify({
        Irradiance:    irradiance,
        TodaysYield:   todaysYield,
        WindSpeed:     windSpeed,
        WindDirection: windDir
    })
};
return [[heatMsg, meteoMsg]];

const temp      = global.get('outdoor_temp');
const humidity  = global.get('outdoor_humidity');
const pressure  = global.get('outdoor_pressure');
const windSpeed = global.get('outdoor_wind_speed');
const windDir   = global.get('outdoor_wind_dir');

// Attendre la première récupération Open-Meteo (once:true → ~0.1s)
if (temp === undefined || temp === null) return null;

const todaysYield = global.get('total_yield_today') || 0;
const irradiance  = global.get('irradiance_wm2')    || 0;

const heatMsg = {
    topic:   'santuario/heat/1/venus',
    payload: JSON.stringify({
        Temperature:     temp,
        TemperatureType: 4,
        Humidity:        humidity,
        Pressure:        pressure
    })
};
const meteoMsg = {
    topic:   'santuario/meteo/venus',
    payload: JSON.stringify({
        Irradiance:    irradiance,
        TodaysYield:   todaysYield,
        WindSpeed:     windSpeed,
        WindDirection: windDir
    })
};
return [[heatMsg, meteoMsg]];

const val = msg.payload && msg.payload.value !== undefined ? msg.payload.value : msg.payload;
if (val === null || val === undefined || isNaN(val)) return null;

let mpptYields = global.get('mppt_yields') || {};
mpptYields[msg.topic] = parseFloat(val) || 0;
global.set('mppt_yields', mpptYields);

const mpptTotal = Object.values(mpptYields).reduce((a, b) => a + b, 0);
global.set('mppt_yield_today', mpptTotal);

// Note: total_yield_today est géré par VRM API (vrm_restore_result_fn)
node.status({fill:'green', shape:'dot', text:'MPPT: ' + mpptTotal.toFixed(2) + ' kWh'});
return [msg, {}];

const val = msg.payload && msg.payload.value !== undefined ? msg.payload.value : msg.payload;
if (val === null || val === undefined || isNaN(val)) return null;

const current = parseFloat(val);
global.set('_last_pvinv_cumul', current);

let baseline = global.get('pvinv_baseline');
const isNewBaseline = (baseline === null || baseline === undefined);

if (isNewBaseline) {
    // Baseline non encore restaurée — poser temporairement, NE PAS persister en retain
    // (la bonne valeur sera restaurée par MQTT retain ou InfluxDB dans les 5 prochaines secondes)
    global.set('pvinv_baseline', current);
    baseline = current;
}

const dailyYield = Math.max(0, parseFloat((current - baseline).toFixed(3)));
global.set('pvinv_yield_today', dailyYield);

node.status({fill:'blue', shape:'dot', text:'PVInv: ' + dailyYield.toFixed(2) + ' kWh (affichage seul)'});

// Output 1 → debug
// Output 2 → persist retain UNIQUEMENT si la baseline était déjà établie (pas une init à froid)
// Output 3 → InfluxDB persist
return [msg, isNewBaseline ? null : {payload: baseline}, {}];

global.set('pvinv_baseline', null);
global.set('pvinv_yield_today', 0);
global.set('mppt_yields', {});
global.set('mppt_yield_today', 0);
global.set('total_yield_today', 0);
node.status({fill:'blue', shape:'dot', text:'Reset minuit OK'});
// Output 1 → rien
// Output 2 → effacer le retained Mosquitto (payload vide = suppression du retained)
return [null, {payload: ''}];

const raw = msg.payload;

// Payload vide = reset minuit (retained effacé), ou pas de baseline stockée
if (raw === '' || raw === null || raw === undefined) {
    global.set('pvinv_baseline', null);
    node.status({fill:'grey', shape:'ring', text:'Pas de baseline (reset ou 1er jour)'});
    return null;
}

const baseline = parseFloat(raw);
if (isNaN(baseline) || baseline <= 0) {
    node.status({fill:'red', shape:'ring', text:'Baseline invalide: ' + raw});
    return null;
}

global.set('pvinv_baseline', baseline);
node.status({fill:'yellow', shape:'dot', text:'Baseline restaurée: ' + baseline.toFixed(1) + ' kWh'});
return null;

const token  = env.get('VRM_TOKEN');
const siteId = env.get('VRM_INSTALLATION_ID') || '865936';

if (!token) {
    node.status({fill:'grey', shape:'ring',
        text:'VRM_TOKEN manquant → ajouter dans .env + make down && make up'});
    return null;
}

// today.totals.kwh = production solaire du jour (MPPT + PVInverter)
msg.url    = `https://vrmapi.victronenergy.com/v2/installations/${siteId}/overallstats`;
msg.method = 'GET';
msg.headers = {
    'X-Authorization': 'Token ' + token
};
node.status({fill:'blue', shape:'dot', text:'Requête VRM API installation ' + siteId});
return msg;

// Vérifier erreur réseau / HTTP
if (msg.statusCode && msg.statusCode >= 400) {
    node.status({fill:'red', shape:'ring', text:'Erreur HTTP VRM: ' + msg.statusCode});
    return null;
}

const data = msg.payload;
if (!data || !data.success) {
    node.status({fill:'red', shape:'ring', text:'Réponse VRM invalide'});
    return null;
}

// today.totals.kwh = production solaire du jour (MPPT + PVInverter), calculé côté serveur Victron
const todayTotals = data.records && data.records.today && data.records.today.totals;
if (!todayTotals || todayTotals.kwh === undefined || todayTotals.kwh === null) {
    node.status({fill:'yellow', shape:'ring', text:'Pas de kwh VRM — vérifier installation_id'});
    return null;
}

const vrmSolarToday = parseFloat(todayTotals.kwh);
if (isNaN(vrmSolarToday) || vrmSolarToday < 0) {
    node.status({fill:'red', text:'Valeur VRM invalide: ' + todayTotals.kwh});
    return null;
}

// VRM = source unique de vérité pour TodaysYield
global.set('total_yield_today', vrmSolarToday);
node.status({fill:'green', shape:'dot', text:'VRM ✓ ' + vrmSolarToday.toFixed(2) + ' kWh'});

// Publier immédiatement vers Venus OS sans attendre le prochain keepalive
const temp      = global.get('outdoor_temp')     || 0;
const irradiance = global.get('irradiance_wm2')  || 0;
const windSpeed  = global.get('outdoor_wind_speed') || 0;
const windDir    = global.get('outdoor_wind_dir')   || 0;

const heatMsg = {
    topic:   'santuario/heat/1/venus',
    payload: JSON.stringify({
        Temperature:     temp,
        TemperatureType: 4,
        Humidity:        global.get('outdoor_humidity')  || 0,
        Pressure:        global.get('outdoor_pressure')  || 0
    })
};
const meteoMsg = {
    topic:   'santuario/meteo/venus',
    payload: JSON.stringify({
        Irradiance:    irradiance,
        TodaysYield:   vrmSolarToday,
        WindSpeed:     windSpeed,
        WindDirection: windDir
    })
};
return [[heatMsg, meteoMsg]];

// Date locale Paris pour filtrer uniquement les données d'aujourd'hui
const now = new Date();
const parisISO = now.toLocaleString('sv-SE', {timeZone: 'Europe/Paris'});
const today = parisISO.substring(0, 10); // YYYY-MM-DD

const token = env.get('INFLUX_TOKEN');
if (!token) {
    node.status({fill:'red', shape:'ring', text:'INFLUX_TOKEN manquant dans docker-compose'});
    return null;
}

const org    = env.get('INFLUX_ORG')    || 'santuario';
const bucket = env.get('INFLUX_BUCKET') || 'daly_bms';

// range -30h pour couvrir les décalages de fuseau horaire
// tag 'day' garantit qu'on ne récupère QUE les données du jour Paris
const fluxQuery = [
    'from(bucket: "' + bucket + '")',
    '  |> range(start: -30h)',
    '  |> filter(fn: (r) => r._measurement == "solar_persist")',
    '  |> filter(fn: (r) => r.day == "' + today + '")',
    '  |> last()'
].join('\n');

msg.url     = 'http://dalybms-influxdb:8086/api/v2/query?org=' + org;
msg.method  = 'POST';
msg.payload = fluxQuery;
msg.headers = {
    'Authorization': 'Token ' + token,
    'Content-Type': 'application/vnd.flux',
    'Accept': 'application/csv'
};
node.status({fill:'blue', shape:'dot', text:'Requête Flux pour ' + today});
return msg;

const csv = msg.payload || '';

// InfluxDB2 retourne du CSV annoté (lignes #datatype, #group, #default + header + données)
const lines = csv.split('\n').filter(l => l.trim() && !l.startsWith('#'));
if (lines.length < 2) {
    node.status({fill:'grey', shape:'ring', text:'Pas de données InfluxDB pour aujourd\'hui'});
    return null;
}

const header = lines[0].split(',');
const fieldIdx = header.findIndex(h => h.trim() === '_field');
const valueIdx = header.findIndex(h => h.trim() === '_value');

if (fieldIdx === -1 || valueIdx === -1) {
    node.error('CSV inattendu: ' + header.join(','));
    node.status({fill:'red', text:'Erreur format CSV InfluxDB'});
    return null;
}

const data = {};
for (let i = 1; i < lines.length; i++) {
    const cols = lines[i].split(',');
    const field = (cols[fieldIdx] || '').trim();
    const value = parseFloat((cols[valueIdx] || '').trim());
    if (field && !isNaN(value)) data[field] = value;
}

// Restaurer pvinv_baseline — valeur critique
if (data.pvinv_baseline !== undefined && data.pvinv_baseline > 0) {
    global.set('pvinv_baseline', data.pvinv_baseline);
}
if (data.mppt_yield_today !== undefined)  global.set('mppt_yield_today',  data.mppt_yield_today || 0);
if (data.pvinv_yield_today !== undefined) global.set('pvinv_yield_today', data.pvinv_yield_today || 0);
if (data.total_yield_today !== undefined) global.set('total_yield_today', data.total_yield_today || 0);

const baseline = data.pvinv_baseline;
const total    = data.total_yield_today || 0;
if (baseline && baseline > 0) {
    node.status({fill:'green', shape:'dot',
        text: `Restauré ✓ baseline=${baseline.toFixed(1)} total=${total.toFixed(2)} kWh`});
} else {
    node.status({fill:'yellow', shape:'ring', text:'Pas de baseline (1er jour ou après reset minuit)'});
}
return null;

const token  = env.get('INFLUX_TOKEN');
const org    = env.get('INFLUX_ORG')    || 'santuario';
const bucket = env.get('INFLUX_BUCKET') || 'daly_bms';

if (!token) return null;

const baseline = global.get('pvinv_baseline');
// Ne pas écrire si la baseline n'est pas encore établie (début de journée)
if (baseline === null || baseline === undefined) return null;

const mppt  = global.get('mppt_yield_today')  || 0;
const pvinv = global.get('pvinv_yield_today') || 0;
const total = global.get('total_yield_today') || 0;

// Tag 'day' = date locale Paris → permet de filtrer par jour au redémarrage
const now = new Date();
const parisISO = now.toLocaleString('sv-SE', {timeZone: 'Europe/Paris'});
const day = parisISO.substring(0, 10); // YYYY-MM-DD

const ts   = Math.floor(Date.now() / 1000);
const line = `solar_persist,day=${day},host=pi5 pvinv_baseline=${baseline},mppt_yield_today=${mppt},pvinv_yield_today=${pvinv},total_yield_today=${total} ${ts}`;

msg.url     = `http://dalybms-influxdb:8086/api/v2/write?org=${org}&bucket=${bucket}&precision=s`;
msg.method  = 'POST';
msg.payload = line;
msg.headers = {
    'Authorization': 'Token ' + token,
    'Content-Type': 'text/plain; charset=utf-8'
};
return msg;
